-- Rebuild propre des référentiels climatiques Mdall.
-- Les tables mdall_climate_* sont des référentiels techniques uniquement.
-- Objectif: supprimer les anciennes lignes seedées avec encodage CP850 mal interprété
-- puis réinsérer un référentiel déterministe en UTF-8.

BEGIN;

TRUNCATE TABLE
  public.mdall_climate_commune_cantons,
  public.mdall_climate_snow_departments,
  public.mdall_climate_snow_canton_overrides,
  public.mdall_climate_wind_departments,
  public.mdall_climate_wind_canton_overrides,
  public.mdall_climate_frost_departments
RESTART IDENTITY;


-- >>> supabase/seed-data/climate/001_commune_canton_2014.sql
-- Generated by scripts/import-climate-data/generate-commune-canton-2014.mjs
-- Source data migrated from former frontend zoning dataset
-- Target: public.mdall_climate_commune_cantons
-- Step 2.1: commune -> canton 2014 mapping

ON CONFLICT (insee_code) DO UPDATE
SET canton_code_2014 = EXCLUDED.canton_code_2014,
    department_code = EXCLUDED.department_code,
    source_payload = EXCLUDED.source_payload,
    updated_at = now();

-- <<< end seed

-- >>> supabase/seed-data/climate/002_canton_2014_names.sql
-- Climate seed data for Supabase
-- Source: france2014.dbf decoded as CP850. Keep this file UTF-8 encoded.
-- Target: public.mdall_climate_commune_cantons lookup rows (insee_code IS NULL).

ON CONFLICT (canton_code_2014) WHERE insee_code IS NULL DO UPDATE
SET canton_name_2014 = EXCLUDED.canton_name_2014,
    canton_name_2014_normalized = EXCLUDED.canton_name_2014_normalized,
    department_code = EXCLUDED.department_code,
    source_payload = coalesce(public.mdall_climate_commune_cantons.source_payload, '{}'::jsonb) || EXCLUDED.source_payload,
    updated_at = now();

-- <<< end seed

-- >>> supabase/seed-data/climate/003_current_canton_names.sql
-- Climate seed data for Supabase
ON CONFLICT (canton_code_2014) WHERE insee_code IS NULL DO UPDATE
SET canton_name_current = EXCLUDED.canton_name_current,
    canton_name_current_normalized = EXCLUDED.canton_name_current_normalized,
    department_code = EXCLUDED.department_code,
    source_payload = coalesce(public.mdall_climate_commune_cantons.source_payload, '{}'::jsonb) || EXCLUDED.source_payload,
    updated_at = now();

-- <<< end seed

-- >>> supabase/seed-data/climate/004_snow_departments.sql
-- Climate seed data for Supabase
ON CONFLICT (department_code, resolved_zone) DO UPDATE
SET source_payload = EXCLUDED.source_payload,
    updated_at = now();

-- <<< end seed

-- >>> supabase/seed-data/climate/005_snow_canton_overrides.sql
-- Climate seed data for Supabase
ON CONFLICT (department_code, canton_name_normalized) DO UPDATE
SET canton_name = EXCLUDED.canton_name,
    resolved_zone = EXCLUDED.resolved_zone,
    source_payload = EXCLUDED.source_payload,
    updated_at = now();

-- <<< end seed

-- >>> supabase/seed-data/climate/006_wind_departments.sql
-- Climate seed data for Supabase
ON CONFLICT (department_code, resolved_zone) DO UPDATE
SET source_payload = EXCLUDED.source_payload,
    updated_at = now();

-- <<< end seed

-- >>> supabase/seed-data/climate/007_wind_canton_overrides.sql
-- Climate seed data for Supabase
ON CONFLICT (department_code, canton_name_normalized) DO UPDATE
SET canton_name = EXCLUDED.canton_name,
    resolved_zone = EXCLUDED.resolved_zone,
    source_payload = EXCLUDED.source_payload,
    updated_at = now();

-- <<< end seed

-- >>> supabase/seed-data/climate/008_frost_departments.sql
-- Climate seed data for Supabase
ON CONFLICT (department_code) DO UPDATE
SET h0_min_m = EXCLUDED.h0_min_m,
    h0_max_m = EXCLUDED.h0_max_m,
    h0_default_m = EXCLUDED.h0_default_m,
    source_payload = EXCLUDED.source_payload,
    updated_at = now();

-- <<< end seed

COMMIT;
